void oled_init(I2C_HandleTypeDef *h){ oi2c=h; wc(0xAE); wc(0x20); wc(0x00); wc(0xB0); wc(0xC8); wc(0x00); wc(0x10); wc(0x40); wc(0x81); wc(0xFF); wc(0xA1); wc(0xA6); wc(0xA8); wc(0x3F); wc(0xA4); wc(0xD3); wc(0x00); wc(0xD5); wc(0xF0); wc(0xD9); wc(0x22); wc(0xDA); wc(0x12); wc(0xDB); wc(0x20); wc(0x8D); wc(0x14); wc(0xAF); oled_clear(); }
void oled_clear(void){ memset(buf,0,sizeof(buf)); }
void oled_refresh(void){ for(uint8_t p=0;p<8;p++){ wc(0xB0|p); wc(0x00); wc(0x10); for(uint8_t c=0;c<OLED_WIDTH;c++)wd(buf[p*OLED_WIDTH+c]); } }
void oled_set_pixel(uint8_t x,uint8_t y,uint8_t clr){ if(x>=OLED_WIDTH||y>=OLED_HEIGHT)return; uint16_t i=x+(y/8)*OLED_WIDTH; if(clr)buf[i]|=(1<<(y%8)); else buf[i]&=~(1<<(y%8)); }
void oled_show_char(uint8_t x,uint8_t y,char c,uint8_t sz){ if(c<32||c>127)c=' '; uint8_t idx=c-32; for(uint8_t i=0;i<5;i++){ uint8_t ln=f5x7[idx][i]; for(uint8_t j=0;j<8;j++){ uint8_t d=(ln>>j)&1; if(sz==1)oled_set_pixel(x+i,y+j,d); else{ oled_set_pixel(x+i*2,y+j*2,d); oled_set_pixel(x+i*2+1,y+j*2,d); oled_set_pixel(x+i*2,y+j*2+1,d); oled_set_pixel(x+i*2+1,y+j*2+1,d); } } } }
void oled_show_string(uint8_t x,uint8_t y,const char *s,uint8_t sz){ uint8_t cw=(sz==1)?6:12; while(*s){ if(x+cw>OLED_WIDTH){ x=0; y+=8*sz; } if(y+8*sz>OLED_HEIGHT)break; oled_show_char(x,y,*s++,sz); x+=cw; } }
void oled_show_num(uint8_t x,uint8_t y,int32_t n,uint8_t l,uint8_t sz){ char b[12]; snprintf(b,sizeof(b),"%*ld",l,(long)n); oled_show_string(x,y,b,sz); }
void oled_draw_rect(uint8_t x,uint8_t y,uint8_t w,uint8_t h){ oled_draw_line(x,y,x+w-1,y); oled_draw_line(x,y,x,y+h-1); oled_draw_line(x+w-1,y,x+w-1,y+h-1); oled_draw_line(x,y+h-1,x+w-1,y+h-1); }
void oled_draw_fill_rect(uint8_t x,uint8_t y,uint8_t w,uint8_t h,uint8_t clr){ for(uint8_t i=0;i<w;i++)for(uint8_t j=0;j<h;j++)oled_set_pixel(x+i,y+j,clr); }
void oled_draw_progress_bar(uint8_t x,uint8_t y,uint8_t w,uint8_t h,uint8_t pct){ if(pct>100)pct=100; uint8_t fw=(uint16_t)w*pct/100; oled_draw_rect(x,y,w,h); oled_draw_fill_rect(x+1,y+1,fw>1?fw-1:0,h>1?h-1:0,1); }
void oled_draw_line(uint8_t x0,uint8_t y0,uint8_t x1,uint8_t y1){ int16_t dx=abs((int16_t)x1-(int16_t)x0),dy=-abs((int16_t)y1-(int16_t)y0),sx=x0<x1?1:-1,sy=y0<y1?1:-1,err=dx+dy,e2; while(1){ oled_set_pixel(x0,y0,1); if(x0==x1&&y0==y1)break; e2=2*err; if(e2>=dy){ err+=dy; x0+=sx; } if(e2<=dx){ err+=dx; y0+=sy; } } }
void oled_draw_lock_icon(uint8_t x,uint8_t y,uint8_t lk){ if(lk){ oled_draw_rect(x+2,y+6,8,8); oled_draw_fill_rect(x+3,y+9,6,4,1); oled_draw_rect(x+4,y+0,4,8); oled_set_pixel(x+4,y+5,0); oled_set_pixel(x+4,y+6,0); oled_set_pixel(x+7,y+5,0); oled_set_pixel(x+7,y+6,0); } else { oled_draw_rect(x+2,y+4,8,10); oled_draw_fill_rect(x+3,y+7,6,3,1); oled_draw_rect(x+4,y+0,4,6); oled_set_pixel(x+1,y+1,1); oled_set_pixel(x+10,y+1,1); } }
void oled_draw_wifi_icon(uint8_t x,uint8_t y,int8_t rssi){ if(rssi>-50){ oled_draw_fill_rect(x,y+6,2,2,1); oled_draw_fill_rect(x+3,y+4,2,4,1); oled_draw_fill_rect(x+6,y+2,2,6,1); oled_draw_fill_rect(x+9,y+0,2,8,1); } else if(rssi>-70){ oled_draw_fill_rect(x,y+6,2,2,1); oled_draw_fill_rect(x+3,y+4,2,4,1); oled_draw_fill_rect(x+6,y+2,2,6,1); } else if(rssi>-85){ oled_draw_fill_rect(x,y+6,2,2,1); oled_draw_fill_rect(x+3,y+4,2,4,1); } else { oled_draw_fill_rect(x,y+6,2,2,1); } }
